const input = $input.first().json;

// Parse input — handle both JSON string and object
let action, agentId;
try {
  const parsed = typeof input.query === 'string' ? JSON.parse(input.query) : input;
  action = parsed.action || input.action;
  agentId = parsed.id || input.id;
} catch(e) {
  action = input.action;
  agentId = input.id;
}

const CDN_BASE = 'https://cdn.jsdelivr.net/gh/freddy-schuetz/n8n-claw-agents@5011c1a/agents';
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';

const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' };

// Helper: update expert_agents discovery entry in agents table
async function updateAgentConfig() {
  try {
    const installed = await helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/agents?key=like.persona:*&select=key,content',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });

    if (!installed || !installed.length) {
      await helpers.httpRequest({
        method: 'PATCH',
        url: SUPABASE_URL + '/rest/v1/agents?key=eq.expert_agents',
        headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({ content: 'No expert agents installed. Use the agent_library tool with action "list_agents" to see available agents, or "install_agent" to install one.' })
      });
      return;
    }

    const lines = installed.map(a => {
      const id = a.key.replace('persona:', '');
      // Extract first line of content as description
      const firstLine = (a.content || '').split('\n').find(l => l.trim() && !l.startsWith('#')) || '';
      return '- **' + id + '**: ' + firstLine.substring(0, 120);
    });

    const instructions = 'You have Expert Agents — specialized sub-agents you can delegate tasks to.\n\n'
      + '## Expert Agent Tool (expert_agent)\n'
      + 'Delegate a task to a specialized expert. Parameters:\n'
      + '- agent: Agent identifier (e.g. "research-expert")\n'
      + '- task: Detailed task description\n'
      + '- context: Relevant conversation context (optional)\n\n'
      + 'The expert works independently and returns a structured result. You then rephrase it in your own tone.\n\n'
      + '## Agent Library (agent_library tool)\n'
      + 'Install/remove expert agents from the catalog.\n'
      + 'Actions: list_agents, install_agent, remove_agent, list_installed\n\n'
      + '## Currently installed Expert Agents (' + installed.length + ' total):\n'
      + lines.join('\n');

    await helpers.httpRequest({
      method: 'PATCH',
      url: SUPABASE_URL + '/rest/v1/agents?key=eq.expert_agents',
      headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ content: instructions })
    });
  } catch(e) {
    // Non-critical — don't fail the whole operation
  }
}

// — ACTION: list_agents —
if (action === 'list_agents') {
  let catalog = [];
  try {
    const index = await helpers.httpRequest({
      method: 'GET',
      url: CDN_BASE + '/index.json',
      headers: { 'Accept': 'application/json' }
    });
    catalog = index.agents || [];
  } catch(e) {
    return [{ json: { error: 'Could not load agent catalog: ' + e.message } }];
  }

  // Cross-reference with installed agents
  try {
    const installed = await helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/agents?key=like.persona:*&select=key',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
    const installedIds = new Set((installed || []).map(r => r.key.replace('persona:', '')));
    catalog = catalog.map(a => ({ ...a, installed: installedIds.has(a.id) }));
  } catch(e) {
    // Show catalog without installed status
  }

  return [{ json: { agents: catalog, total: catalog.length } }];

// — ACTION: install_agent —
} else if (action === 'install_agent') {
  if (!agentId) {
    return [{ json: { error: 'Parameter "id" is missing. Example: {"action":"install_agent","id":"research-expert"}' } }];
  }

  const personaKey = 'persona:' + agentId;

  // Check if already installed
  try {
    const existing = await helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/agents?key=eq.' + personaKey + '&select=key',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
    if (existing && existing.length > 0) {
      return [{ json: { error: 'Agent "' + agentId + '" is already installed.' } }];
    }
  } catch(e) { /* proceed */ }

  // Fetch persona from CDN
  let persona;
  try {
    persona = await helpers.httpRequest({
      method: 'GET',
      url: CDN_BASE + '/' + agentId + '/persona.json',
      headers: { 'Accept': 'application/json' }
    });
  } catch(e) {
    return [{ json: { error: 'Agent "' + agentId + '" not found in catalog.' } }];
  }

  if (persona.format !== 'n8n-claw-agent') {
    return [{ json: { error: 'Unknown agent format: ' + (persona.format || 'none') } }];
  }

  // Insert persona into agents table
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/agents',
      headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        key: personaKey,
        content: persona.content
      })
    });
  } catch(e) {
    return [{ json: { error: 'Database insert failed: ' + e.message } }];
  }

  // Update expert_agents discovery
  await updateAgentConfig();

  return [{ json: {
    success: true,
    message: 'Agent "' + agentId + '" successfully installed. You can now delegate tasks to it using the expert_agent tool with agent="' + agentId + '".',
    agent_id: agentId,
    display_name: persona.display_name || agentId
  } }];

// — ACTION: remove_agent —
} else if (action === 'remove_agent') {
  if (!agentId) {
    return [{ json: { error: 'Parameter "id" is missing. Example: {"action":"remove_agent","id":"research-expert"}' } }];
  }

  const personaKey = 'persona:' + agentId;

  // Check if installed
  try {
    const existing = await helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/agents?key=eq.' + personaKey + '&select=key',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
    if (!existing || existing.length === 0) {
      return [{ json: { error: 'Agent "' + agentId + '" is not installed.' } }];
    }
  } catch(e) {
    return [{ json: { error: 'Database query failed: ' + e.message } }];
  }

  // Delete from agents table
  try {
    await helpers.httpRequest({
      method: 'DELETE',
      url: SUPABASE_URL + '/rest/v1/agents?key=eq.' + personaKey,
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
  } catch(e) {
    return [{ json: { error: 'Delete failed: ' + e.message } }];
  }

  // Update expert_agents discovery
  await updateAgentConfig();

  return [{ json: {
    success: true,
    message: 'Agent "' + agentId + '" successfully removed.',
    agent_id: agentId
  } }];

// — ACTION: list_installed —
} else if (action === 'list_installed') {
  let installed;
  try {
    installed = await helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/agents?key=like.persona:*&select=key,content,updated_at',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
  } catch(e) {
    return [{ json: { error: 'Database query failed: ' + e.message } }];
  }

  const agents = (installed || []).map(a => {
    const id = a.key.replace('persona:', '');
    const firstLine = (a.content || '').split('\n').find(l => l.trim() && !l.startsWith('#')) || '';
    return {
      id,
      description: firstLine.substring(0, 200),
      updated_at: a.updated_at
    };
  });

  return [{ json: { agents, total: agents.length } }];

} else {
  return [{ json: {
    error: 'Unknown action: "' + (action || '') + '". Available: list_agents, install_agent, remove_agent, list_installed',
    examples: [
      '{"action":"list_agents"}',
      '{"action":"install_agent","id":"research-expert"}',
      '{"action":"remove_agent","id":"research-expert"}',
      '{"action":"list_installed"}'
    ]
  } }];
}
